    Eigen::Vector<float, 2> normalize_input(    const Eigen::Vector<float, 2>& in  ){
        Eigen::Vector<float, 2> res;
        res = (in - input_offset).array() / input_scale.array();
        return res;
    };

    Eigen::Vector<float, 1> denormalize_output( const Eigen::Vector<float, 1>& out ){
        Eigen::Vector<float, 1> res;
        res = out.array()*output_scale.array();
        res = res + output_offset;
        return res;
    };
